-- バナナ品種データ 110件
-- けんゆー公開記事を優先し、ProMusa/PROSEA等の公開情報を補助して作成。
-- Supabase SQL Editorで part1 から順番に実行してください。

begin;

insert into public.fruits (
  name_ja, name_en, slug, scientific_name, family_name, origin, description,
  growth_habit, flower_description, fruit_description, cultivation_summary,
  okinawa_suitability, public_notes, private_notes, is_public
) values (
  'バナナ',
  'Banana',
  'banana',
  'Musa spp.',
  'バショウ科',
  '東南アジアから太平洋地域を中心に多様化',
  'バナナはデザート用、調理用、観賞用まで非常に多様な品種群をもつ熱帯果樹です。果樹図鑑では食味だけでなく、草丈、用途、沖縄での風対策や病害リスクも見比べられるように整理します。',
  '多年草。偽茎は結実後に枯れ、吸芽で更新する。',
  '花序は苞に包まれて下垂し、雌花が果房を形成する。',
  '品種により小型から大型、デザート向きから調理向きまで幅広い。',
  '沖縄では生育しやすい一方、台風、バナナセセリ、バンチートップ、パナマ病への注意が重要。',
  '沖縄向き。防風、排水、株分け更新、病害虫確認を栽培の中心にする。',
  null,
  '初期バナナ品種110件はけんゆー公開記事とProMusa/PROSEA等の公開情報を参照して作成。',
  true
)
on conflict (slug) do update set
  name_ja = excluded.name_ja,
  name_en = excluded.name_en,
  scientific_name = excluded.scientific_name,
  family_name = excluded.family_name,
  origin = excluded.origin,
  description = excluded.description,
  growth_habit = excluded.growth_habit,
  flower_description = excluded.flower_description,
  fruit_description = excluded.fruit_description,
  cultivation_summary = excluded.cultivation_summary,
  okinawa_suitability = excluded.okinawa_suitability,
  private_notes = excluded.private_notes,
  is_public = excluded.is_public,
  updated_at = now();

with banana as (
  select id from public.fruits where slug = 'banana'
)
insert into public.cultivars (
  fruit_id,
  name_ja,
  name_en,
  slug,
  origin,
  description,
  fruit_size,
  taste,
  texture,
  aroma,
  harvest_season,
  tree_vigor,
  difficulty,
  okinawa_suitability,
  container_suitability,
  beginner_suitability,
  kenyu_comment,
  public_notes,
  private_notes,
  is_public,
  is_for_sale
)
select
  banana.id,
  v.column1,
  v.column2,
  v.column3,
  v.column4,
  v.column5,
  v.column6,
  v.column7,
  v.column8,
  v.column9,
  v.column10,
  v.column11,
  v.column12,
  v.column13,
  v.column14,
  v.column15,
  v.column16,
  v.column17,
  v.column18,
  v.column19,
  v.column20
from banana
cross join (values
  ('島バナナ', 'Okinawan island banana', 'okinawan-island-banana', '沖縄', '島バナナは沖縄に関連するデザートタイプのバナナです。甘みと酸味のバランスがよいの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '小ぶり。草姿: 中型。', '甘みと酸味のバランスがよい。', 'ややもっちり', '華やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。比較的作りやすい候補として試しやすい。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', '島バナナは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://okinawan-avocado.com/category/%e6%9e%9c%e6%a8%b9/%e3%83%90%e3%83%8a%e3%83%8a/ / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
  ('ナムワ', 'Kluai Nam Wa', 'kluai-nam-wa', 'タイ', 'ナムワはタイに関連するデザート・調理兼用タイプのバナナです。甘みが濃く加熱にも向くの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 中型。', '甘みが濃く加熱にも向く。', 'もっちり', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート・調理兼用。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。比較的作りやすい候補として試しやすい。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '調理用品種として目的を決めて育てたい。完熟生食だけを期待すると印象が変わる。', 'ナムワは「デザート・調理兼用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Pisang+Awak / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
  ('ドワーフナムワ', 'Dwarf Namwah', 'dwarf-namwah', 'タイ系', 'ドワーフナムワはタイ系に関連するデザート・調理兼用タイプのバナナです。甘く家庭栽培で扱いやすいの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 小型。', '甘く家庭栽培で扱いやすい。', 'もっちり', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '小型。家庭栽培での管理サイズ: 低。', '用途: デザート・調理兼用。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。低めの株なので家庭菜園や鉢でも管理しやすい。比較的作りやすい候補として試しやすい。', '鉢栽培でも検討しやすい。根詰まりと水切れに注意し、毎年の株分け候補を見ておく。', '初心者にも試しやすい候補。まずは排水のよい場所と防風を整える。', 'ドワーフナムワは「デザート・調理兼用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Pisang+Awak / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
  ('銀バナナ', 'Kluai Namwa Nuan', 'kluai-namwa-nuan', 'タイ系', '銀バナナはタイ系に関連するデザートタイプのバナナです。濃厚で食味評価が高いの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 中型。', '濃厚で食味評価が高い。', 'なめらか', '甘い香り', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。比較的作りやすい候補として試しやすい。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', '銀バナナは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://okinawan-avocado.com/2025/01/25/kauai_namwa_nuan/ / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
  ('ナムワアイスクリーム', 'Namwah Ice Cream', 'namwah-ice-cream', 'タイ系', 'ナムワアイスクリームはタイ系に関連するデザートタイプのバナナです。クリーミーで甘みが強いの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 中型。', 'クリーミーで甘みが強い。', 'ねっとり', 'バニラ様', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。比較的作りやすい候補として試しやすい。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'ナムワアイスクリームは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://okinawan-avocado.com/2021/10/08/banana_ikehara_san/ / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
  ('アイスクリームバナナ', 'Blue Java', 'blue-java', '東南アジア', 'アイスクリームバナナは東南アジアに関連するデザートタイプのバナナです。甘くクリーミーの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '太め。草姿: 大型。', '甘くクリーミー。', 'アイスクリーム状', 'バニラ様', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '大型。家庭栽培での管理サイズ: 高。', '用途: デザート。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。大株になりやすく、防風と十分な株間を確保したい。比較的作りやすい候補として試しやすい。', '鉢では長期維持が難しいため、露地または大鉢で短期更新を前提にしたい。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'アイスクリームバナナは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Diversity+of+banana+cultivars+portal / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
  ('合掌バナナ', 'Praying Hands', 'praying-hands', '太平洋地域', '合掌バナナは太平洋地域に関連するデザート・調理兼用タイプのバナナです。やさしい甘みの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '密着した房。草姿: 中型。', 'やさしい甘み。', 'しっかり', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート・調理兼用。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '調理用品種として目的を決めて育てたい。完熟生食だけを期待すると印象が変わる。', '合掌バナナは「デザート・調理兼用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://okinawan-avocado.com/2021/10/31/lingkit/ / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
  ('リンキット', 'Lingkit', 'lingkit', 'タイ系', 'リンキットはタイ系に関連するデザート・調理兼用タイプのバナナです。加熱でも生食でも楽しめるの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '密着した房。草姿: 中型。', '加熱でも生食でも楽しめる。', 'しっかり', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート・調理兼用。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '調理用品種として目的を決めて育てたい。完熟生食だけを期待すると印象が変わる。', 'リンキットは「デザート・調理兼用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://okinawan-avocado.com/2021/10/31/lingkit/ / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
  ('クルアイテパノム', 'Kluai Thepanom', 'kluai-thepanom', 'タイ', 'クルアイテパノムはタイに関連するデザート・調理兼用タイプのバナナです。甘みがあり個性的の品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '密着した房。草姿: 中型。', '甘みがあり個性的。', 'しっかり', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート・調理兼用。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '調理用品種として目的を決めて育てたい。完熟生食だけを期待すると印象が変わる。', 'クルアイテパノムは「デザート・調理兼用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://okinawan-avocado.com/2021/10/31/lingkit/ / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
  ('ミャンマーバナナ', 'Musa Phama Haek Kuk', 'musa-phama-haek-kuk', 'ミャンマー', 'ミャンマーバナナはミャンマーに関連するデザートタイプのバナナです。癖が少なくすっきりの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 中型。', '癖が少なくすっきり。', 'なめらか', '軽い香り', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。比較的作りやすい候補として試しやすい。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'ミャンマーバナナは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://okinawan-avocado.com/2021/10/31/musa_phama_haek_kuk/ / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
  ('野菜バナナ', 'Vegetable banana', 'vegetable-banana', '東南アジア系', '野菜バナナは東南アジア系に関連する調理用タイプのバナナです。加熱で甘みと香りが出るの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '太め。草姿: 大型。', '加熱で甘みと香りが出る。', 'ほくほく', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '大型。家庭栽培での管理サイズ: 高。', '用途: 調理用。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。大株になりやすく、防風と十分な株間を確保したい。', '鉢では長期維持が難しいため、露地または大鉢で短期更新を前提にしたい。', '調理用品種として目的を決めて育てたい。完熟生食だけを期待すると印象が変わる。', '野菜バナナは「調理用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://okinawan-avocado.com/2022/04/27/vegetable_banana/ / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
  ('三尺バナナ', 'Dwarf Cavendish', 'dwarf-cavendish', 'キャベンディッシュ系', '三尺バナナはキャベンディッシュ系に関連するデザートタイプのバナナです。なじみ深い甘さの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 小型。', 'なじみ深い甘さ。', 'なめらか', '軽い', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '小型。家庭栽培での管理サイズ: 低。', '用途: デザート。耐寒性目安: 弱め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。低めの株なので家庭菜園や鉢でも管理しやすい。冬よりも病害と風害に注意したい。', '鉢栽培でも検討しやすい。根詰まりと水切れに注意し、毎年の株分け候補を見ておく。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', '三尺バナナは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Diversity+of+banana+cultivars+portal / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
  ('キャベンディッシュ', 'Cavendish', 'cavendish', '東南アジア起源の商用品種群', 'キャベンディッシュは東南アジア起源の商用品種群に関連するデザートタイプのバナナです。穏やかな甘さで流通向きの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 中型。', '穏やかな甘さで流通向き。', 'なめらか', '軽い', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート。耐寒性目安: 弱め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。冬よりも病害と風害に注意したい。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'キャベンディッシュは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Diversity+of+banana+cultivars+portal / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
  ('グランドナイン', 'Grande Naine', 'grande-naine', 'キャベンディッシュ系', 'グランドナインはキャベンディッシュ系に関連するデザートタイプのバナナです。安定した甘みの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 中型。', '安定した甘み。', 'なめらか', '軽い', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート。耐寒性目安: 弱め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。冬よりも病害と風害に注意したい。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'グランドナインは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Diversity+of+banana+cultivars+portal / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false),
